const http = require('http');
const fs = require('fs/promises');
const url = require('url');

const PORT = 3000;
const HOST = 'localhost';

// Buat server
const server = http.createServer(async (req, res) => {
  // Parse URL: pathname, query string
  const parsedUrl = url.parse(req.url, true);
  const pathname = parsedUrl.pathname;
  const method = req.method;

  console.log(`${method} ${pathname}`);

  // Set header response default
  res.setHeader('Content-Type', 'application/json');
  res.setHeader('Access-Control-Allow-Origin', '*');

  // Routing manual
  if (pathname === '/' && method === 'GET') {
    res.writeHead(200);
    res.end(JSON.stringify({ pesan: 'Selamat datang di API saya!' }));

  } else if (pathname === '/mahasiswa' && method === 'GET') {
    try {
      const data = await fs.readFile('./data/mahasiswa.json', 'utf8');
      res.writeHead(200);
      res.end(data);
    } catch {
      res.writeHead(500);
      res.end(JSON.stringify({ error: 'Gagal membaca data' }));
    }

  } else if (pathname === '/mahasiswa' && method === 'POST') {
    // Baca body dari request
    let body = '';
    req.on('data', chunk => { body += chunk.toString(); });
    req.on('end', () => {
      try {
        const mahasiswaBaru = JSON.parse(body);
        res.writeHead(201);
        res.end(JSON.stringify({ pesan: 'Berhasil ditambahkan', data: mahasiswaBaru }));
      } catch {
        res.writeHead(400);
        res.end(JSON.stringify({ error: 'Body tidak valid JSON' }));
      }
    });

  } else {
    // 404 untuk semua path yang tidak dikenali
    res.writeHead(404);
    res.end(JSON.stringify({ error: 'Endpoint tidak ditemukan' }));
  }
});

// Jalankan server
server.listen(PORT, HOST, () => {
  console.log(`Server berjalan di http://${HOST}:${PORT}`);
});

