const EventEmitter = require('events');

// ==========================================
// DASAR EventEmitter
// ==========================================
const emitter = new EventEmitter();

// Daftarkan listener
emitter.on('dataMasuk', (data) => {
  console.log('Data diterima:', data);
});

emitter.on('error', (err) => {
  console.error('Terjadi error:', err.message);
});

// Listener sekali pakai
emitter.once('koneksi', () => {
  console.log('Pertama kali terhubung!');
  // Tidak akan dipanggil lagi meski emit('koneksi') dipanggil berkali-kali
});

// Pancarkan event
emitter.emit('dataMasuk', { nama: 'Budi', nilai: 85 });
emitter.emit('dataMasuk', { nama: 'Siti', nilai: 92 });
emitter.emit('koneksi'); // Dipanggil
emitter.emit('koneksi'); // TIDAK dipanggil (once)

// ==========================================
// CONTOH NYATA: Custom Logger
// ==========================================
class Logger extends EventEmitter {
  info(pesan) {
    const log = { level: 'INFO', pesan, waktu: new Date().toISOString() };
    console.log(`[INFO] ${pesan}`);
    this.emit('log', log); // beri tahu semua listener bahwa ada log baru
  }

  error(pesan) {
    const log = { level: 'ERROR', pesan, waktu: new Date().toISOString() };
    console.error(`[ERROR] ${pesan}`);
    this.emit('log', log);
    this.emit('error_terjadi', log); // event khusus untuk error
  }
}

const logger = new Logger();

