const fs = require('fs');
const zlib = require('zlib'); // untuk kompresi
const path = require('path');

// ==========================================
// READABLE STREAM
// ==========================================
const readStream = fs.createReadStream('./data/file-besar.csv', {
  encoding: 'utf8',
  highWaterMark: 64 * 1024  // ukuran chunk: 64KB (default 16KB)
});

let totalBaris = 0;
readStream.on('data', (chunk) => {
  // Setiap chunk adalah potongan file ~64KB
  const baris = chunk.split('\n').length;
  totalBaris += baris;
  console.log(`Chunk diterima: ${chunk.length} karakter`);
});

readStream.on('end', () => {
  console.log(`Selesai! Estimasi total baris: ${totalBaris}`);
});

readStream.on('error', (err) => {
  console.error('Stream error:', err.message);
});

// ==========================================
